INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-d0d1b9a2-moex-00285', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '乙公司X2年初應收帳款總額$50,000，備抵損失$3,000（貸餘）。X2年度賖銷金額$600,000。期末估計損 失率為 3%，期末提列預期信用減損損失為$2,100。若乙公司 X2 年度未發生呆帳沖銷，試問當年度應收 帳款收現之金額為何？', '["$471,000", "$450,000", "$510,000", "$480,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00286', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於3月20日，接受其顧客的一張票據作為延遲付款之用。該票據面額$50,000、利率5%、90天到 期。到了5月19日，甲公司因臨時需要現金，而以該票據向往來銀行進行貼現，銀行要求的貼現利率為 8%。若該票據貼現不具追索權，下列有關貼現的敘述，何者正確？', '["該票據的到期值為$50,000", "該票據貼現之貼現息為$337.5", "貼現之時，公司可以收到的現金為$49,663", "貼現之時，公司應入帳的利息收入為$387.5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00287', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司X2年期末存貨低估$100,000，對X3年之影響為何？', '["銷貨毛利不影響", "銷貨毛利低估$100,000", "進貨成本低估$100,000", "銷貨成本低估$100,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00288', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司存貨採定期盤存制，X3 年底結帳後，發現下列期末存貨錯誤：①X1 年期末存貨低估$10,000', '["X2 年期末存貨高估$20,000", "X3 年期末存貨高估$30,000。在不考慮所得稅的情況下，若甲公司 X3 年度原帳列淨利為$300,000，則X3年正確之淨利金額為何？", "$250,000", "$270,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00289', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司採用永續盤存制、加權平均法，在1月1日有1,800件存貨，成本為每件$18。1月份的進貨及銷', '["1月4日銷貨1,350件，每件售價$28", "1月7日進貨 900件，每件成本$20", "1月15 日進貨900件，每件成本$22", "1月29日銷貨900件，每件售價$32。甲公司1月31日期末存貨成本應 為何？"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00290', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X3年5月24日以每罐售價$160賒銷A客戶100罐咖啡，該筆賒銷交易付款條件為2/10，n/30。 X3年5月30日A客戶退回15罐咖啡，X3年6月2日A客戶償還該筆賒銷交易總價四分之一欠款，X3 年6月3日A客戶償還該筆賒銷交易總價四分之二欠款，X3年6月4日A客戶又退回5罐咖啡，X3年 6月5日A客戶將剩餘欠款清償。甲公司自該筆賒銷交易所收取之現金應為多少？', '["$12,596", "$12,732", "$12,800", "$13,396"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00291', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X3年4月1日以$500,000購入乙公司發行之公司債，另支付證券交易稅$15,000及手續費$8,000， 甲公司將其分類為透過損益按公允價值衡量之金融資產，則該項公司債投資之原始認列金額是多少？', '["$500,000", "$508,000", "$515,000", "$523,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00292', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '有關債務工具投資類型下，透過其他綜合損益按公允價值衡量之金融資產，下列敘述何者錯誤？', '["若改為透過損益按公允價值衡量，對其帳面金額無影響", "對本期淨利的影響和按攤銷後成本衡量的金融資產相同", "已經按公允價值衡量，所以不需認列減損", "對本期綜合損益的影響和透過損益按公允價值衡量之金融資產相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00293', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丙公司於X2年5月12日購入丁公司普通股1,600股，每股價格為$35，並支付手續費$250。丙公司將該 股票投資指定為透過其他綜合損益按公允價值衡量的權益工具投資。X2年底丁公司普通股之每股市價為 $38。丙公司於X3年5月15日收到丁公司所發放的股票股利5%及現金股利每股$2，當日丁公司股價每 股$30，並於X3年6月2日以每股$40將該股票投資全數出售。該股票投資對於丙公司X3年度稅前淨利 之影響為何？', '["增加$3,200", "增加$5,600", "增加$11,200", "增加$13,600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00294', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丁公司X4年2月5日以每股$20購買戊公司普通股15,000股，並分類為「透過其他綜合損益按公允價值 衡量之股票投資」。X4年9月15日戊公司發放每股$2之現金股利（該股利非屬成本退回）及10%股票 股利。X4年12月31日戊公司股票每股公允價值為$23。在不考慮所得稅的情況下，該股票投資對丁公 司X4年度本期其他綜合損益之影響數為何？', '["$45,000", "$79,500", "$49,500", "$15,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
